class Solution:
    def movesToMakeZigzag(self, nums):
        INF = float('inf')
        best = INF
        for parity in (0, 1):
            cost = 0
            for i in range(len(nums)):
                if i % 2 == parity:
                    left = nums[i - 1] if i - 1 >= 0 else INF
                    right = nums[i + 1] if i + 1 < len(nums) else INF
                    need = min(left, right)
                    if nums[i] >= need:
                        cost += nums[i] - need + 1
            best = min(best, cost)
        return best

