class Solution:
    def movesToMakeZigzag(self, nums):
        n = len(nums)
        def cost(valley_parity):
            total = 0
            for i in range(n):
                if i % 2 != valley_parity:
                    continue
                left = nums[i - 1] if i > 0 else 10**9
                right = nums[i + 1] if i < n - 1 else 10**9
                m = min(left, right)
                if nums[i] >= m:
                    total += nums[i] - m + 1
            return total
        return min(cost(0), cost(1))

