var movesToMakeZigzag = function(nums) {
    const n = nums.length;
    const cost = (parity) => {
        let total = 0;
        for (let i = 0; i < n; i++) {
            if (i % 2 !== parity) continue;
            const left = i > 0 ? nums[i - 1] : 1e9;
            const right = i < n - 1 ? nums[i + 1] : 1e9;
            const m = Math.min(left, right);
            if (nums[i] >= m) total += nums[i] - m + 1;
        }
        return total;
    };
    return Math.min(cost(0), cost(1));
};
